sys_script_include.script:
function HtmlRenderPrintableQRCodesA4(strPayload)
{
    var HtmlRenderQRCode = x_snc_devtools.HtmlRenderQRCode;
    var HtmlRenderPageA4 = x_snc_devtools.HtmlRenderPageA4;

    var strHtml = '';
    var strGrid = '';

    var nCols = 3;
    var nRows = 4;

    var strSingleQR = HtmlRenderQRCode(strPayload, 5, 'cm');

    var strBorder = '0.3mm dashed #aaa';

    var aTableStyles = [
        'width:19cm',
        'border-collapse:collapse',
        'margin:0 auto',
        'table-layout:fixed'
    ];
    var strTableStyle = aTableStyles.join(';');

    var aCellStyles = [
        'width:6.33cm',
        'height:6.33cm',
        'box-sizing:border-box',
        'text-align:center',
        'vertical-align:middle',
        'padding:1mm',
        'border:' + strBorder
    ];
    var strCellStyle = aCellStyles.join(';');

    // Wrap QR in a centering div — handles both block and inline QR output
    var aWrapStyles = [
        'display:table',
        'margin:0 auto'
    ];
    var strWrapStyle = aWrapStyles.join(';');

    var strWrappedQR = '<div style="' + strWrapStyle + '">' + strSingleQR + '</div>';

    strGrid += '<table style="' + strTableStyle + '">';
    for (var row = 0; row < nRows; row++)
    {
        strGrid += '<tr>';
        for (var col = 0; col < nCols; col++)
        {
            strGrid += '<td style="' + strCellStyle + '">';
            strGrid += strWrappedQR;
            strGrid += '</td>';
        }
        strGrid += '</tr>';
    }
    strGrid += '</table>';

    strHtml = strGrid;
    strHtml = HtmlRenderPageA4(strHtml, 1, 1);

    return strHtml;
}
